+    fn test_at_capacity_after_poisoning() {
+        let pool = poison_pool_mutex();
+
+        // at_capacity() should recover and return correct value
+        // Pool has 2 connections, max is 5, so not at capacity
+        assert!(!pool.at_capacity());
+    }
+
